#include <stdio.h>
#include <stdlib.h>

int longestSubarraySum(int *arr, int n, int k) {
    // hashmap using simple array of structs could be used, but for clarity we use a dynamic hash via unordered map in C++.
    // Here we implement O(n^2) fallback as placeholder; in practice use a hash table.
    int max_len = 0;
    for (int i = 0; i < n; ++i) {
        long long sum = 0;
        for (int j = i; j < n; ++j) {
            sum += arr[j];
            if (sum == k) {
                int len = j - i + 1;
                if (len > max_len) max_len = len;
            }
        }
    }
    return max_len;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int *arr = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        printf("%d\n", longestSubarraySum(arr, n, k));
        free(arr);
    }
    return 0;
}

