#include <bits/stdc++.h>
using namespace std;

int longestSubarraySum(const vector<int>& arr, int k) {
    unordered_map<long long,int> firstPos;
    long long sum = 0;
    int maxLen = 0;
    for (int i = 0; i < (int)arr.size(); ++i) {
        sum += arr[i];
        if (sum == k) maxLen = i + 1;
        auto it = firstPos.find(sum - k);
        if (it != firstPos.end())
            maxLen = max(maxLen, i - it->second);
        if (firstPos.find(sum) == firstPos.end())
            firstPos[sum] = i;
    }
    return maxLen;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int n, k; cin >> n >> k;
        vector<int> arr(n);
        for (int &x : arr) cin >> x;
        cout << longestSubarraySum(arr, k) << '\n';
    }
    return 0;
}

