import java.io.*;
import java.util.*;

public class Main {
    private static int longestSubarraySum(int[] arr, int k) {
        Map<Long,Integer> firstPos = new HashMap<>();
        long sum = 0;
        int maxLen = 0;
        for (int i = 0; i < arr.length; i++) {
            sum += arr[i];
            if (sum == k) maxLen = i + 1;
            Long need = sum - k;
            Integer idx = firstPos.get(need);
            if (idx != null) maxLen = Math.max(maxLen, i - idx);
            firstPos.putIfAbsent(sum, i);
        }
        return maxLen;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int k = Integer.parseInt(st.nextToken());
            int[] arr = new int[n];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < n; i++) arr[i] = Integer.parseInt(st.nextToken());
            sb.append(longestSubarraySum(arr, k)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

