import sys

def longest_subarray_sum(arr, k):
    first_pos = {}
    s = 0
    max_len = 0
    for i, v in enumerate(arr):
        s += v
        if s == k:
            max_len = i + 1
        need = s - k
        if need in first_pos:
            max_len = max(max_len, i - first_pos[need])
        if s not in first_pos:
            first_pos[s] = i
    return max_len

